import * as tf from '@tensorflow/tfjs';

// Создаём тензор
const tensor = tf.tensor([1, 2, 3, 4], [2, 2]);
console.log('Тензор:', tensor.arraySync());

// Простая модель для демонстрации
async function createAndUseModel() {
    // Создаём последовательную модель
    const model = tf.sequential();
    model.add(tf.layers.dense({units: 10, inputShape: [4]}));
    model.add(tf.layers.dense({units: 1}));

    // Компилируем модель
    model.compile({
        optimizer: 'sgd',
        loss: 'meanSquaredError'
    });

    // Пример данных для обучения
    const xs = tf.randomNormal([100, 4]);
    const ys = tf.randomNormal([100, 1]);

    // Обучаем модель
    await model.fit(xs, ys, {
        epochs: 5
    });
    console.log('Модель обучена!');
}

createAndUseModel();
